import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onClose: () => void;
  isARMode: boolean;
  toggleARMode: () => void;
}

export const GestureController: React.FC<GestureControllerProps> = ({ 
  onControl, 
  onClose,
  isARMode,
  toggleARMode
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loading, setLoading] = useState(true);
  const [permissionError, setPermissionError] = useState(false);
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);

  const prevHandDistanceRef = useRef<number | null>(null);
  const [statusMessage, setStatusMessage] = useState<string>("正在开启魔法手势...");

  useEffect(() => {
    let isMounted = true;
    const init = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );
        if (!isMounted) return;
        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 2
        });
        if (isMounted) startWebcam();
      } catch (error) {
        console.error("Init Error:", error);
        if (isMounted) setLoading(false);
      }
    };
    init();
    return () => {
      isMounted = false;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (videoRef.current?.srcObject) {
        (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
      }
    };
  }, []);

  const startWebcam = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { width: 640, height: 480, facingMode: "user" } 
      });
      if (videoRef.current) videoRef.current.srcObject = stream;
      setLoading(false);
      setStatusMessage("手势雷达已就绪！");
    } catch (err) {
      setPermissionError(true);
      setLoading(false);
    }
  };

  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current || videoRef.current.readyState < 2) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }
    const result = landmarkerRef.current.detectForVideo(videoRef.current, performance.now());
    processGestures(result);
    draw(result);
    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (result: HandLandmarkerResult) => {
    const hands = result.landmarks;
    if (!hands || hands.length === 0) {
      onControl(0, 0, 'rotate');
      prevHandDistanceRef.current = null;
      return;
    }

    // 双手缩放逻辑 (Spread = Zoom In, Pinch = Zoom Out)
    if (hands.length === 2) {
      const h1 = hands[0][9]; 
      const h2 = hands[1][9];
      const dist = Math.hypot(h1.x - h2.x, h1.y - h2.y);
      if (prevHandDistanceRef.current !== null) {
        const delta = dist - prevHandDistanceRef.current;
        if (Math.abs(delta) > 0.005) {
           // 正 delta 代表张开 -> 放大 (Zoom In)
           // 负 delta 代表合拢 -> 缩小 (Zoom Out)
           onControl(0, delta * 450, 'zoom'); 
           setStatusMessage(delta > 0 ? "✨ 正在拉近观察" : "🔭 正在远离观察");
        }
      }
      prevHandDistanceRef.current = dist;
      return;
    }

    // 单手旋转逻辑
    if (hands.length === 1) {
      prevHandDistanceRef.current = null;
      const cursor = hands[0][9]; 
      const x = 1.0 - cursor.x; 
      const y = cursor.y;
      let dx = 0, dy = 0;
      const DEADZONE = 0.12; 
      if (Math.abs(x - 0.5) > DEADZONE) dx = (x - 0.5) * 2.5;
      if (Math.abs(y - 0.5) > DEADZONE) dy = (y - 0.5) * 2.5;
      onControl(dx, dy, 'rotate');
      setStatusMessage(dx !== 0 || dy !== 0 ? "🕹️ 正在驾驶飞船" : "✋ 悬停中");
    }
  };

  const draw = (result: HandLandmarkerResult) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // 镜像绘制背景
    if (!isARMode && videoRef.current) {
        ctx.save();
        ctx.scale(-1, 1);
        ctx.drawImage(videoRef.current, -canvas.width, 0, canvas.width, canvas.height);
        ctx.restore();
        ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
    }

    // 绘制手部骨骼 (亮蓝色科技感)
    if (result.landmarks) {
      for (const landmarks of result.landmarks) {
        ctx.strokeStyle = "#22d3ee"; // 亮青色
        ctx.lineWidth = 4;
        ctx.lineJoin = "round";
        HandLandmarker.HAND_CONNECTIONS.forEach(conn => {
          const s = landmarks[conn.start];
          const e = landmarks[conn.end];
          ctx.beginPath();
          ctx.moveTo((1 - s.x) * canvas.width, s.y * canvas.height);
          ctx.lineTo((1 - e.x) * canvas.width, e.y * canvas.height);
          ctx.stroke();
        });
        ctx.fillStyle = "#ffffff";
        landmarks.forEach(lm => {
           ctx.beginPath();
           ctx.arc((1 - lm.x) * canvas.width, lm.y * canvas.height, 3, 0, 2 * Math.PI);
           ctx.fill();
        });
      }
    }
  };

  return (
    <>
      <video 
        ref={videoRef} 
        className={`fixed inset-0 w-full h-full object-cover -scale-x-100 transition-opacity duration-500
          ${isARMode ? 'z-[-10] opacity-100' : 'z-[-20] opacity-0 pointer-events-none'}
        `}
        autoPlay playsInline muted
        onLoadedData={predictWebcam}
      />

      {/* AR 模式下的毛玻璃背景遮罩 */}
      {isARMode && (
         <div className="fixed inset-0 w-full h-full bg-blue-950/40 backdrop-blur-[2px] z-[-9] pointer-events-none" />
      )}

      {/* 手势反馈预览窗口 */}
      <canvas 
        ref={canvasRef} width={320} height={240}
        className={`fixed bottom-24 right-6 w-44 h-34 rounded-2xl border-2 border-cyan-400/50 shadow-[0_0_20px_rgba(34,211,238,0.3)] z-50 bg-black/60 pointer-events-none transition-all
           ${isARMode ? 'opacity-80 scale-90' : 'opacity-100'}
        `}
      />

      <div className="absolute bottom-6 right-6 z-50 flex flex-col items-end gap-4 pointer-events-auto">
        <div className="bg-slate-900/90 backdrop-blur-md border border-cyan-500/40 text-cyan-300 px-5 py-2.5 rounded-2xl font-bold shadow-2xl flex items-center gap-3 animate-pulse">
           <span className="w-2.5 h-2.5 rounded-full bg-cyan-400"></span>
           <span className="text-sm tracking-widest uppercase font-mono">{statusMessage}</span>
        </div>

        <div className="flex items-center gap-4">
           <button 
             onClick={toggleARMode}
             className={`h-14 px-6 rounded-2xl font-bold text-sm shadow-xl border-2 transition-all flex items-center gap-2
               ${isARMode ? 'bg-cyan-500 text-black border-white shadow-cyan-500/50' : 'bg-slate-800 text-white border-slate-600'}`}
           >
             <span>{isARMode ? "🪐 现实模式" : "📹 混合现实 (AR)"}</span>
           </button>
           <button onClick={onClose} className="w-14 h-14 bg-red-500 text-white rounded-2xl flex items-center justify-center shadow-xl border-2 border-white/20">✕</button>
        </div>
      </div>
    </>
  );
};

import React, { useRef, useMemo, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Color, MathUtils, Group } from 'three';

export const AsteroidBelt: React.FC<{ isPaused: boolean; simulationSpeed: number }> = ({ isPaused, simulationSpeed }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const groupRef = useRef<Group>(null);
  const count = 1200; // 增加密度
  const dummy = useMemo(() => new Object3D(), []);

  const particles = useMemo(() => {
    const temp = [];
    // 小行星带位于火星 (110) 和 木星 (180) 之间
    const minRadius = 135; 
    const maxRadius = 155; 

    for (let i = 0; i < count; i++) {
      const r = MathUtils.randFloat(minRadius, maxRadius);
      const theta = MathUtils.randFloat(0, Math.PI * 2);
      const x = r * Math.cos(theta);
      const z = -r * Math.sin(theta);
      const y = MathUtils.randFloatSpread(2.5);
      const scale = MathUtils.randFloat(0.15, 0.5);
      const rotation = [Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI];
      temp.push({ x, y, z, scale, rotation });
    }
    return temp;
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
      const color = new Color();
      const palette = ['#E5E7EB', '#D1D5DB', '#9CA3AF', '#C4B5FD'];
      particles.forEach((p, i) => {
        dummy.position.set(p.x, p.y, p.z);
        dummy.rotation.set(p.rotation[0], p.rotation[1], p.rotation[2]);
        dummy.scale.set(p.scale, p.scale, p.scale);
        dummy.updateMatrix();
        meshRef.current!.setMatrixAt(i, dummy.matrix);
        color.set(palette[Math.floor(Math.random() * palette.length)]).multiplyScalar(0.7);
        meshRef.current!.setColorAt(i, color);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;
      if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
    }
  }, [particles, dummy]);

  useFrame((state, delta) => {
    if (groupRef.current && !isPaused) {
      groupRef.current.rotation.y += delta * 0.005 * simulationSpeed;
    }
  });

  return (
    <group ref={groupRef}>
      <instancedMesh ref={meshRef} args={[undefined, undefined, count]}>
        <dodecahedronGeometry args={[0.5, 0]} />
        <meshStandardMaterial roughness={0.8} metalness={0.1} color="#ffffff" emissive="#111" emissiveIntensity={0.5} />
      </instancedMesh>
    </group>
  );
};
